import { useRef, useState, useCallback } from "react";
import type { ProviderFormat } from "../types/core";
import { parseSSEStream } from "../utils/parseSSE";

export interface UseStreamOptions {
  /** Endpoint to POST to, or a function returning a Response directly */
  api: string | (() => Promise<Response>);
  /** Request body — serialized as JSON when api is a string */
  body?: Record<string, unknown>;
  /** Additional headers */
  headers?: HeadersInit;
  /** Provider format for SSE parsing. Defaults to 'openai' */
  providerFormat?: ProviderFormat;
  /** Custom SSE parser — override if providerFormat doesn't cover your case */
  parseChunk?: (chunk: string) => string | null;
  /** Called when the stream starts */
  onStart?: () => void;
  /** Called with each decoded text delta */
  onChunk?: (chunk: string) => void;
  /** Called with full accumulated content on completion */
  onFinish?: (content: string) => void;
  /** Called on error */
  onError?: (error: Error) => void;
  /** Flush mode for downstream processing */
  flushMode?: "immediate" | "raf";
}

export interface UseStreamReturn {
  content: string;
  isStreaming: boolean;
  error: Error | null;
  abort: () => void;
  start: (overrideBody?: Record<string, unknown>) => Promise<void>;
  reset: () => void;
}

export function useStream(options: UseStreamOptions): UseStreamReturn {
  const [content, setContent] = useState("");
  const [isStreaming, setIsStreaming] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const abortControllerRef = useRef<AbortController | null>(null);
  const contentRef = useRef("");

  const abort = useCallback(() => {
    abortControllerRef.current?.abort();
  }, []);

  const reset = useCallback(() => {
    contentRef.current = "";
    setContent("");
    setError(null);
    setIsStreaming(false);
  }, []);

  const start = useCallback(
    async (overrideBody?: Record<string, unknown>) => {
      // Abort any in-flight request
      abortControllerRef.current?.abort();
      const controller = new AbortController();
      abortControllerRef.current = controller;

      contentRef.current = "";
      setContent("");
      setError(null);
      setIsStreaming(true);
      options.onStart?.();

      try {
        let response: Response;
        if (typeof options.api === "function") {
          response = await options.api();
        } else {
          response = await fetch(options.api, {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              ...options.headers,
            },
            body: JSON.stringify({ ...options.body, ...overrideBody }),
            signal: controller.signal,
          });
        }

        if (!response.ok) {
          let message = `HTTP ${response.status}`;
          try {
            const errBody = (await response.json()) as { error?: { message?: string } };
            message = errBody.error?.message ?? message;
          } catch {
            // ignore parse error
          }
          throw new Error(message);
        }

        const reader = response.body?.getReader();
        if (!reader) throw new Error("Response body is not readable");

        const decoder = new TextDecoder();
        const format = options.providerFormat ?? "openai";

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          const chunk = decoder.decode(value, { stream: true });
          for (const delta of parseSSEStream(chunk, format)) {
            if (options.parseChunk) {
              // custom parser takes priority
              const custom = options.parseChunk(delta);
              if (custom !== null) {
                contentRef.current += custom;
                setContent(contentRef.current);
                options.onChunk?.(custom);
              }
            } else {
              contentRef.current += delta;
              setContent(contentRef.current);
              options.onChunk?.(delta);
            }
          }
        }

        options.onFinish?.(contentRef.current);
      } catch (err) {
        if (err instanceof Error && err.name === "AbortError") {
          // User-triggered abort — silent
          return;
        }
        const error = err instanceof Error ? err : new Error(String(err));
        setError(error);
        options.onError?.(error);
      } finally {
        setIsStreaming(false);
      }
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [options]
  );

  return { content, isStreaming, error, abort, start, reset };
}

// Core types for @inferface/hooks
// ---------------------------------------------------------------------------

export type StreamTransport = (
  input: RequestInfo | URL,
  init?: RequestInit
) => Promise<Response>;

export type MessageRole = "user" | "assistant" | "system" | "tool";

// ---------------------------------------------------------------------------
// Rich Content / Content Parts
// ---------------------------------------------------------------------------

/** Data shape for an embedded chart */
export interface ChartData {
  type: "bar" | "line" | "pie" | "scatter" | string;
  labels?: string[];
  datasets: {
    label?: string;
    data: number[];
    [key: string]: unknown;
  }[];
  options?: Record<string, unknown>;
}

export type ContentPart =
  | { type: "text"; text: string }
  | { type: "image_url"; image_url: { url: string; alt?: string } }
  | { type: "chart"; data: ChartData }
  | { type: "custom"; component: string; props: unknown };

export interface Message {
  id: string;
  role: MessageRole;
  /**
   * String for plain-text messages; ContentPart[] for rich/multimodal content.
   * Hooks always return string during streaming accumulation.
   * Use `extractText(content)` to get a plain string in either case.
   */
  content: string | ContentPart[];
  createdAt?: Date;
  toolCallId?: string;
  toolCalls?: ToolCall[];
}

export interface ToolCall {
  id: string;
  type: "function";
  function: {
    name: string;
    arguments: string; // JSON string — stream accumulates this
  };
}

export interface ToolResult {
  toolCallId: string;
  result: unknown;
  error?: Error;
}

export type ProviderFormat = "openai" | "anthropic" | "custom";

/**
 * Extract a plain text string from Message.content regardless of form.
 * Concatenates all `text` parts for ContentPart[] content.
 */
export function extractText(content: string | ContentPart[]): string {
  if (typeof content === "string") return content;
  return content
    .filter((p): p is { type: "text"; text: string } => p.type === "text")
    .map((p) => p.text)
    .join("");
}

/**
 * Parse OpenAI SSE chunk.
 * Format: data: {"choices":[{"delta":{"content":"hello"},...}]}
 * Sentinel: data: [DONE]
 */
export function parseOpenAIChunk(raw: string): string | null {
  if (raw === "[DONE]") return null;
  try {
    const parsed = JSON.parse(raw) as {
      choices?: Array<{ delta?: { content?: string } }>;
    };
    return parsed.choices?.[0]?.delta?.content ?? null;
  } catch {
    return null;
  }
}

/**
 * Parse Anthropic SSE chunk.
 * Requires the event type from the preceding `event:` line.
 */
export function parseAnthropicChunk(raw: string, eventType?: string): string | null {
  if (eventType === "message_stop" || eventType === "message_delta") return null;
  try {
    const parsed = JSON.parse(raw) as {
      type?: string;
      delta?: { type?: string; text?: string };
    };
    if (parsed.type === "content_block_delta" && parsed.delta?.type === "text_delta") {
      return parsed.delta.text ?? null;
    }
    return null;
  } catch {
    return null;
  }
}

/**
 * Parse a raw SSE stream body into text deltas.
 * Handles both OpenAI and Anthropic formats.
 */
export function* parseSSEStream(
  chunk: string,
  format: "openai" | "anthropic" | "custom"
): Generator<string> {
  const lines = chunk.split("\n");
  let currentEvent: string | undefined;

  for (const line of lines) {
    if (line.startsWith("event:")) {
      currentEvent = line.slice(6).trim();
      continue;
    }
    if (line.startsWith("data:")) {
      const data = line.slice(5).trim();
      if (!data) continue;

      let text: string | null = null;
      if (format === "openai") {
        text = parseOpenAIChunk(data);
      } else if (format === "anthropic") {
        text = parseAnthropicChunk(data, currentEvent);
      }

      if (text !== null) {
        yield text;
      }
      currentEvent = undefined;
    }
  }
}
